mapper.insert:
        /*
             SQL ID : insertAtflList
             설  명 : 첨부파일목록 저장
        */
		INSERT INTO TB_LMS_ATFL (
			  ATFL_ID
			, REF_ID
			, ATFL_REPO_ID
			, ATFL_SEQNO
			, FILENM
			, FILE_EXT
			, FILE_PATH
			, FILE_SAVNM
			, FILE_SIZE
			, FILE_TYCD
			, CNVSN_FILE
			, ETC_INFO1
			, ETC_INFO2
			, ETC_INFO3
			, MIME_TYCD
			, THMB_FILE_PATH
			, THMB_FILENM
			, DWLD_CNT
			, DELYN
			, RGTR_ID
			, REG_DTTM
			, MDFR_ID
			, MOD_DTTM
        )

			SELECT
				  #{item.atflId}
				, #{item.refId}
				, #{item.atflRepoId}
				, #{item.atflSeqno}
				, #{item.filenm}
				, #{item.fileExt}
				, #{item.filePath}
				, #{item.fileSavnm}
				, #{item.fileSize}
				, #{item.fileTycd}
				, #{item.cnvsnFile}
				, #{item.etcInfo1}
				, #{item.etcInfo2}
				, #{item.etcInfo3}
				, #{item.mimeTycd}
				, #{item.thmbFilePath}
				, #{item.thmbFilenm}
				, #{item.dwldCnt}
				, #{item.delyn}
				, #{item.rgtrId}
				, FN_DTTM()
				, #{item.mdfrId}
				, FN_DTTM()
			FROM DUAL
